import datetime
from dateutil.parser import parse

dates = ["2025.05.01", "2026.03.11", "2025.08.15", "2026.01.11", "2025.12.25", "2025.11.20", "2026.03.02", "2026.05.01"]

def process_dates():
    for census_date in dates:
        parsed_date = parse(census_date)
        days_to_go = parsed_date.date() - datetime.date.today()

        if days_to_go.days < 0:
            print(f'{parsed_date.date()} is an Invalid Date')
        elif days_to_go.days == 0:
            print("Today is the census date")
        elif days_to_go.days > 0:
            print(f'{parsed_date.date()} is {days_to_go.days} days to go')

process_dates()
